import Order from '../models/Order.js';
import MenuItem from '../models/MenuItem.js';

// @desc    Create new order
// @route   POST /api/orders
export const addOrderItems = async (req, res) => {
  try {
    const { items, totalPrice, deliveryAddress, phone, paymentMethod } = req.body;

    if (!items || items.length === 0) {
      res.status(400);
      throw new Error('No order items');
    }

    // Verify each item and populate name/price
    const populatedItems = await Promise.all(
      items.map(async (item) => {
        const menuItem = await MenuItem.findById(item.menuItem);
        if (!menuItem) {
          throw new Error(`Menu item not found: ${item.menuItem}`);
        }
        return {
          menuItem: item.menuItem,
          name: menuItem.name,
          quantity: item.quantity,
          price: menuItem.price,
          options: item.options || [],
        };
      })
    );

    const order = new Order({
      user: req.user._id,
      items: populatedItems,
      totalPrice,
      deliveryAddress,
      phone,
      paymentMethod,
    });

    const createdOrder = await order.save();
    res.status(201).json(createdOrder);
  } catch (error) {
    res.status(400);
    throw error;
  }
};

// @desc    Get order by ID
// @route   GET /api/orders/:id
export const getOrderById = async (req, res) => {
  try {
    const order = await Order.findById(req.params.id).populate('user', 'name email phone');
    
    if (!order) {
      res.status(404);
      throw new Error('Order not found');
    }

    // Check authorization: customer can only view own orders, admin can view any
    if (req.user.role !== 'admin' && order.user._id.toString() !== req.user._id.toString()) {
      res.status(403);
      throw new Error('Not authorized to view this order');
    }

    res.json(order);
  } catch (error) {
    res.status(error.status || 500);
    throw error;
  }
};

// @desc    Update order to paid
// @route   PUT /api/orders/:id/pay
export const updateOrderToPaid = async (req, res) => {
  try {
    const order = await Order.findById(req.params.id);

    if (!order) {
      res.status(404);
      throw new Error('Order not found');
    }

    order.isPaid = true;
    order.paidAt = Date.now();

    const updatedOrder = await order.save();
    res.json(updatedOrder);
  } catch (error) {
    res.status(500);
    throw error;
  }
};

// @desc    Update order status (admin only)
// @route   PUT /api/orders/:id/status
export const updateOrderStatus = async (req, res) => {
  try {
    const { status } = req.body;
    const order = await Order.findById(req.params.id);

    if (!order) {
      res.status(404);
      throw new Error('Order not found');
    }

    order.status = status;
    if (status === 'Delivered') {
      order.deliveredAt = Date.now();
    }

    const updatedOrder = await order.save();

    // Emit socket event to the user's room
    const io = req.app.get('io');
    if (io) {
      io.to(order.user.toString()).emit('orderStatusUpdated', {
        orderId: order._id,
        status: order.status,
      });
    }

    res.json(updatedOrder);
  } catch (error) {
    res.status(400);
    throw error;
  }
};

// @desc    Get logged in user orders
// @route   GET /api/orders/myorders
export const getMyOrders = async (req, res) => {
  try {
    const orders = await Order.find({ user: req.user._id }).sort('-createdAt');
    res.json(orders);
  } catch (error) {
    res.status(500);
    throw error;
  }
};

// @desc    Get all orders (admin only)
// @route   GET /api/orders
export const getOrders = async (req, res) => {
  try {
    const orders = await Order.find({}).populate('user', 'id name email').sort('-createdAt');
    res.json(orders);
  } catch (error) {
    res.status(500);
    throw error;
  }
};
